mapper.select:
/* oms-master-orderCode-sql-oracle.xml - selectTOrderMstOrdCdHd */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK, ORDERCOMHDKEY, ORDERCOMHNM, DELYN, INSERTDATE, INSERTURKEY, UPDATEDATE, UPDATEURKEY FROM TORDER_MST_ORCD_HD
#{SEARCH_CONDITION}
AND ORDERCOMHDKEY = #{ordercomhdkey}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY UPDATEDATE DESC , ORDERCOMHDKEY ASC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

		/* oms-master-orderCode-sql-oracle.xml - selectTOrderMstOrdCdHdCount */
        SELECT count(1)
          FROM TORDER_MST_ORCD_HD


			 	   #{SEARCH_CONDITION}

/* oms-master-orderCode-sql-oracle.xml - selectTOrderMstOrdCdDt */ SELECT TB1.ORDERCOMHDKEY ,TB2.ORDERCOMDTKEY ,TB2.ORDERCOMDTNM ,TB2.ORDERCOMDTVAL ,TB2.DTKEYORD ,TB2.DELYN ,TB2.CMT ,TB2.LAKEY ,TB2.INSERTDATE ,TB2.INSERTURKEY ,TB2.UPDATEDATE ,TB2.UPDATEURKEY FROM TORDER_MST_ORCD_HD TB1 JOIN TORDER_MST_ORCD_DT TB2 ON TB1.ORDERCOMHDKEY = TB2.ORDERCOMHDKEY AND TB1.ORDERCOMHDKEY = #{ordercomhdkey}
AND TB2.ORDERCOMDTKEY = #{ordercomdtkey}
AND TB2.DELYN = #{delyn}
ORDER BY CASE WHEN TB2.LAKEY = 'KOR' THEN 0 ELSE 1 END, TB2.LAKEY, TB2.DTKEYORD ASC

/* oms-master-orderCode-sql-oracle.xml - selectTOrderMstOrdCdDTCount */ SELECT COUNT(1) FROM ( SELECT TB1.ORDERCOMHDKEY ,TB2.ORDERCOMDTKEY ,TB2.ORDERCOMDTNM ,TB2.ORDERCOMDTVAL ,TB2.DTKEYORD ,TB2.CMT ,TB2.LAKEY ,TB2.INSERTDATE ,TB2.INSERTURKEY ,TB2.UPDATEDATE ,TB2.UPDATEURKEY FROM TORDER_MST_ORCD_HD TB1 JOIN TORDER_MST_ORCD_DT TB2 ON TB1.ORDERCOMHDKEY = TB2.ORDERCOMHDKEY AND TB1.ORDERCOMHDKEY = #{ordercomhdkey}
AND TB2.ORDERCOMDTKEY = #{ordercomdtkey}
AND TB2.DELYN = #{delyn}
)

/* oms-master-orderCode-sql-oracle.xml - checkOrderCodeInfo */
SELECT count(1)
  FROM TORDER_MST_ORCD_HD

 WHERE ORDERCOMHDKEY = #{ordercomhdkey}

/* oms-master-orderCode-sql-oracle.xml - checkDetailOrderCodeInfo */
SELECT count(1)
  FROM TORDER_MST_ORCD_DT
  WHERE ORDERCOMHDKEY = #{ordercomhdkey}

	AND ORDERCOMDTKEY = #{ordercomdtkey}


	AND 	LAKEY = #{lakey}

mapper.insert:
		/* oms-master-orderCode-sql-oracle.xml - insertOrderCodeInfo */
		INSERT INTO TORDER_MST_ORCD_HD
		(
		      ORDERCOMHDKEY
		    , ORDERCOMHNM
		    , DELYN
		    , INSERTDATE
			, INSERTURKEY
   		  	, UPDATEDATE
			, UPDATEURKEY
		)
		VALUES
		(
		     #{ordercomhdkey}
		    ,#{ordercomhnm}
		    ,COALESCE(#{delyn}, 'N')
			,#{sysdate}
			,#{surkey}
			,#{sysdate}
			,#{surkey}
		)

		/* oms-master-orderCode-sql-oracle.xml - insertDetailOrderCodeInfo */
		INSERT INTO TORDER_MST_ORCD_DT
		(
		      ORDERCOMHDKEY
		    , ORDERCOMDTKEY
		    , LAKEY
		    , DTKEYORD
		    , ORDERCOMDTNM
		    , ORDERCOMDTVAL
		    , CMT
		    , DELYN
		    , INSERTDATE
			, INSERTURKEY
   		  	, UPDATEDATE
			, UPDATEURKEY
		)
		VALUES
		(
		     #{ordercomhdkey}
		    ,#{ordercomdtkey}
		    ,#{lakey}
		    ,#{dtkeyord}
		    ,#{ordercomdtnm}
		    ,#{ordercomdtval}
		    ,#{cmt}
		    ,COALESCE(#{delyn}, 'N')
			,#{sysdate}
			,#{surkey}
			,#{sysdate}
			,#{surkey}
		)

mapper.update:
/* oms-master-orderCode-sql-oracle.xml - updateOrderCodeInfo */
UPDATE TORDER_MST_ORCD_HD
   SET ORDERCOMHNM = #{ordercomhnm}
     , DELYN = #{delyn}
	 , UPDATEDATE   = #{sysdate}
	 , UPDATEURKEY  = #{surkey}
 WHERE ORDERCOMHDKEY  = #{ordercomhdkey}

/* oms-master-orderCode-sql-oracle.xml - updateDetailOrderCodeInfo */
UPDATE TORDER_MST_ORCD_DT
   SET DTKEYORD = #{dtkeyord}
   	  ,ORDERCOMDTNM  = #{ordercomdtnm}
   	  ,ORDERCOMDTVAL = #{ordercomdtval}
   	  ,CMT   = #{cmt}
   	  ,DELYN = #{delyn}
	  ,UPDATEDATE   = #{sysdate}
	  ,UPDATEURKEY  = #{surkey}
 WHERE ORDERCOMHDKEY   = #{ordercomhdkey}
   AND ORDERCOMDTKEY   = #{ordercomdtkey}
   AND 	LAKEY = #{lakey}

mapper.delete:
/* oms-master-orderCode-sql-oracle.xml - deleteOrderCodeInfo */
UPDATE TORDER_MST_ORCD_HD
SET DELYN = #{delyn}
  , UPDATEDATE   = #{sysdate}
  , UPDATEURKEY  = #{surkey}
 WHERE ORDERCOMHDKEY  = #{ordercomhdkey}

		/* oms-master-orderCode-sql-oracle.xml - deleteDetailOrderCodeInfo */
		UPDATE TORDER_MST_ORCD_DT
		SET DELYN = #{delyn}
		  , UPDATEDATE   = #{sysdate}
		  , UPDATEURKEY  = #{surkey}
		 WHERE ORDERCOMHDKEY  = #{ordercomhdkey}

    	 	AND ORDERCOMDTKEY = #{ordercomdtkey}


    	 	AND 	LAKEY = #{lakey}
